from rest_framework import generics, permissions
from rest_framework.response import Response
from rest_framework import status
from .models import Course
from .serializers import CourseSerializer

class CourseListView(generics.ListCreateAPIView):
    serializer_class = CourseSerializer
    permission_classes = [permissions.IsAuthenticatedOrReadOnly]

    def get_queryset(self):
        queryset = Course.objects.select_related('instructor')
        category = self.request.query_params.get('category')
        if category:
            queryset = queryset.filter(category=category)
        return queryset.order_by('-created_at')

    def create(self, request, *args, **kwargs):
        serializer = self.get_serializer(data=request.data)
        serializer.is_valid(raise_exception=True)
        self.perform_create(serializer)
        return Response(
            serializer.data,
            status=status.HTTP_201_CREATED
        )

from openai import OpenAI
import numpy as np

client = OpenAI()

# Step 1: Embed your documents
def embed(text: str) -> list[float]:
    response = client.embeddings.create(
        model="text-embedding-3-small",
        input=text
    )
    return response.data[0].embedding

# Step 2: Find most relevant document
def cosine_similarity(a, b):
    return np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b))

def retrieve(query: str, docs: list[dict]) -> str:
    query_embedding = embed(query)
    scored = [
        (cosine_similarity(query_embedding, d['embedding']), d['text'])
        for d in docs
    ]
    return sorted(scored, reverse=True)[0][1]

# Step 3: Generate answer with context
def rag_answer(query: str, docs: list[dict]) -> str:
    context = retrieve(query, docs)
    response = client.chat.completions.create(
        model="gpt-4o",
        messages=[
            {"role": "system", "content": f"Answer using this context: {context}"},
            {"role": "user", "content": query}
        ]
    )
    return response.choices[0].message.content

// Define your API response shape
interface ApiResponse<T> {
  data: T;
  error: string | null;
  status: 'success' | 'error' | 'loading';
}

interface Course {
  id: string;
  title: string;
  price: number;
  category: 'python' | 'devops' | 'react';
  enrolledAt?: Date;  // optional field
}

// TypeScript catches mismatches at compile time
async function fetchCourse(id: string): Promise<ApiResponse<Course>> {
  const res = await fetch(`/api/courses/${id}`);
  return res.json();
}

// Usage — TypeScript knows exactly what .data contains
const result = await fetchCourse('course-123');
if (result.status === 'success') {
  console.log(result.data.title);    // ✅ TypeScript knows this exists
  console.log(result.data.unknown);  // ❌ TypeScript error at compile time
}
